sys_ws_operation.operation_script:
(function process(request, response) {
    var body = request.body.data;

    // ==========================================
    // MODULE 1: PUBLIC CITIZEN SELF-REGISTRATION
    // ==========================================
    if (body.type === 'registration') {
        var checkUser = new GlideRecord('sys_user');
        checkUser.addQuery('email', body.email);
        checkUser.query();
        if (checkUser.hasNext()) {
            response.setStatus(200);
            return {
                success: false,
                error: "This email address is already registered."
            };
        }

        var userGr = new GlideRecord('sys_user');
        userGr.initialize();
        userGr.first_name = body.name.split(' ')[0] || body.name;
        userGr.last_name = body.name.split(' ').slice(1).join(' ') || '.';
        userGr.email = body.email;
        userGr.user_name = body.email;
        userGr.user_password.setDisplayValue(body.password);
        userGr.active = true;

        var newUserSysId = userGr.insert();

        if (newUserSysId) {
            var roleGr = new GlideRecord('sys_user_has_role');
            roleGr.initialize();
            roleGr.user = newUserSysId;
            roleGr.role.setDisplayValue('snc_external');
            roleGr.insert();

            response.setStatus(201);
            return {
                result: {
                    success: true,
                    user_id: body.email
                }
            };
        }

        response.setStatus(500);
        return {
            success: false,
            error: "System failed to allocate user row."
        };
    }

    // ==========================================
    // MODULE 2: TASK DATA SUBMISSION (CLEAN TARGET)
    // ==========================================
    else {
        var reporterName = body.reporter_name || body.name || "Anonymous Citizen";
        var reporterEmail = body.reporter_email || body.email || "";
        var reporterPhone = body.reporter_phone || "";
        var physicalLoc = body.hazard_location || body.location || "";
        var shortDesc = body.short_description || "Public Community Hazard Report";
        var longDesc = body.description || "";

        // PRIVILEGED GLOBAL OVERRIDE (Bypasses ACL constraint loops perfectly)
        var gr = new global.GlideRecord('x_1834272_emergenc_disaster_assistance_request');
        gr.initialize();
        gr.setWorkflow(false); 

        gr.u_citizen_name = reporterName;
        gr.u_citizen_email = reporterEmail;
        gr.u_physical_location = physicalLoc;

        // Map the fields that your widget layout passes over
        gr.u_summary = shortDesc;
        gr.u_details = "Phone: " + reporterPhone + "\n\n" + longDesc;

        var incomingAssistance = body.assistance_type ? body.assistance_type.toString() : '';
        var normalizedValue = 'temporary_housing';
        var assignedGroup = 'Disaster Assistance Team';

        if (incomingAssistance === 'temporary_housing' || incomingAssistance === 'Temporary Housing') {
            normalizedValue = 'temporary_housing';
            assignedGroup = 'Disaster Housing Team';
        } else if (incomingAssistance === 'emergency_funding' || incomingAssistance === 'Emergency Funding' || incomingAssistance === 'Financial Assistance') {
            normalizedValue = 'emergency_funding';
            assignedGroup = 'Disaster Finance Team';
        } else if (incomingAssistance === 'food_medical_supplies' || incomingAssistance === 'Food & Supplies' || incomingAssistance === 'Medical Assistance' || incomingAssistance === 'Food/Medical Supplies') {
            normalizedValue = 'food_medical_supplies';
            assignedGroup = 'Disaster Logistics Team';
        }

        gr.u_assistance_type = normalizedValue;
        gr.u_booking_status = 'Pending Staff Verification';
        gr.assignment_group.setDisplayValue(assignedGroup);

        var newSysId = gr.insert();

        if (newSysId) {
            response.setStatus(201);
            return {
                result: {
                    success: true,
                    sys_id: newSysId
                }
            };
        }
    }

    response.setStatus(500);
    return {
        success: false,
        error: "Database transaction failed."
    };
})(request, response);
